/**
 * Apply user-chosen thread colours on top of an original pattern.
 *
 * Colour mapping (same as index.html):
 *   #7B030A → color1Hex
 *   #FFFFFF → color2Hex
 *   #CCCCCC → stripeHex  (stripe patterns)  OR  color3Hex  (classic-3)
 *   #D0D0D0 → color3Hex  (stripe-3 only)
 *   #552B06 → unchanged  (replaced at render time by the leather colour)
 */
export const applyColorsToPattern = (
  originalPattern: string[][],
  color1Hex: string | null,
  color2Hex: string | null,
  color3Hex: string | null,
  stripeHex: string | null
): string[][] => {
  const isStripePattern = stripeHex !== null

  return originalPattern.map((row) =>
    row.map((cell) => {
      if (cell === '#7B030A' && color1Hex) return color1Hex
      if (cell === '#FFFFFF' && color2Hex) return color2Hex
      if (cell === '#CCCCCC') {
        if (isStripePattern && stripeHex) return stripeHex
        if (!isStripePattern && color3Hex) return color3Hex
      }
      if (cell === '#D0D0D0' && color3Hex) return color3Hex
      return cell
    })
  )
}